     1→/**
     2→ * Folders Store
     3→ *
     4→ * Zustand store for managing folder hierarchy
     5→ * Persisted to IndexedDB via syncedStorage
     6→ * Supports unlimited nesting depth
     7→ */
     8→
     9→import { create } from 'zustand';
    10→import { persist, createJSONStorage } from 'zustand/middleware';
    11→import { v4 as uuidv4 } from 'uuid';
    12→import type {
    13→  Folder,
    14→  FolderUpdate,
    15→  FolderTreeNode,
    16→} from '../types/notes';
    17→import { FOLDER_CONSTANTS } from '../types/notes';
    18→import { createSyncedStorage } from '../lib/syncedStorage';
    19→import { logger } from '../services/logger';
    20→// Import at module level - Vite handles circular deps better than CommonJS
    21→import { useNotesStore } from './useNotesStore';
    22→
    23→const log = logger.module('FoldersStore');
    24→
    25→/**
    26→ * Folders Store State
    27→ */
    28→interface FoldersStore {
    29→  // State
    30→  folders: Record<string, Folder>; // Map of folder ID -> Folder
    31→  activeFolderId: string | null; // Currently selected folder
    32→  expandedFolderIds: Set<string>; // Expanded folders in tree view
    33→
    34→  // Actions - CRUD
    35→  createFolder: (params?: Partial<Folder>) => Folder;
    36→  getFolder: (id: string) => Folder | undefined;
    37→  updateFolder: (id: string, updates: FolderUpdate) => void;
    38→  deleteFolder: (id: string, deleteNotes?: boolean) => void;
    39→  duplicateFolder: (id: string) => Folder | null;
    40→
    41→  // Actions - Hierarchy
    42→  moveFolder: (folderId: string, newParentId: string | null) => void;
    43→  getChildren: (parentId: string | null) => Folder[];
    44→  getParent: (folderId: string) => Folder | null;
    45→  getPath: (folderId: string) => Folder[];
    46→  getDepth: (folderId: string) => number;
    47→  getFlatTree: () => Folder[];
    48→  getTree: () => FolderTreeNode[];
    49→
    50→  // Actions - Expand/Collapse
    51→  toggleExpanded: (id: string) => void;
    52→  expandFolder: (id: string) => void;
    53→  collapseFolder: (id: string) => void;
    54→  expandAll: () => void;
    55→  collapseAll: () => void;
    56→  expandPath: (folderId: string) => void; // Expand all ancestors
    57→
    58→  // Actions - UI state
    59→  setActiveFolder: (id: string | null) => void;
    60→
    61→  // Actions - Utility
    62→  canMoveFolder: (folderId: string, targetParentId: string | null) => boolean;
    63→  isDescendantOf: (folderId: string, ancestorId: string) => boolean;
    64→  exportFolders: () => Folder[];
    65→  importFolders: (folders: Folder[], merge: boolean) => void;
    66→  clearAllFolders: () => void;
    67→}
    68→
    69→/**
    70→ * Default folder values
    71→ */
    72→const createDefaultFolder = (overrides?: Partial<Folder>): Folder => {
    73→  const now = new Date();
    74→  return {
    75→    id: uuidv4(),
    76→    parentId: null,
    77→    name: FOLDER_CONSTANTS.DEFAULT_NAME,
    78→    createdAt: now,
    79→    updatedAt: now,
    80→    isExpanded: true, // New folders expanded by default
    81→    ...overrides,
    82→  };
    83→};
    84→
    85→/**
    86→ * Build tree structure from flat folder list
    87→ */
    88→const buildTree = (
    89→  folders: Folder[],
    90→  parentId: string | null,
    91→  depth: number = 0,
    92→  notesCountMap: Record<string, number> = {}
    93→): FolderTreeNode[] => {
    94→  const children = folders.filter((f) => f.parentId === parentId);
    95→
    96→  return children.map((folder) => {
    97→    const subtree = buildTree(folders, folder.id, depth + 1, notesCountMap);
    98→    const noteCount = notesCountMap[folder.id] || 0;
    99→    const totalNoteCount =
   100→      noteCount + subtree.reduce((sum, child) => sum + child.totalNoteCount, 0);
   101→
   102→    return {
   103→      ...folder,
   104→      children: subtree,
   105→      depth,
   106→      path: [], // Will be filled in by getPath if needed
   107→      noteCount,
   108→      totalNoteCount,
   109→    };
   110→  });
   111→};
   112→
   113→/**
   114→ * Create the Folders store
   115→ */
   116→export const useFoldersStore = create<FoldersStore>()(
   117→  persist(
   118→    (set, get) => ({
   119→      // Initial state
   120→      folders: {},
   121→      activeFolderId: null,
   122→      expandedFolderIds: new Set<string>(),
   123→
   124→      // CRUD Operations
   125→      createFolder: (params) => {
   126→        const newFolder = createDefaultFolder(params);
   127→
   128→        // Check max depth
   129→        const depth = get().getDepth(newFolder.parentId || '');
   130→        if (depth >= FOLDER_CONSTANTS.MAX_DEPTH) {
   131→          log.warn('Max folder depth reached', { maxDepth: FOLDER_CONSTANTS.MAX_DEPTH });
   132→          return newFolder; // Return but don't create
   133→        }
   134→
   135→        set((state) => ({
   136→          folders: {
   137→            ...state.folders,
   138→            [newFolder.id]: newFolder,
   139→          },
   140→          expandedFolderIds: new Set([
   141→            ...state.expandedFolderIds,
   142→            newFolder.id,
   143→          ]),
   144→          activeFolderId: newFolder.id, // Auto-select new folder
   145→        }));
   146→
   147→        // Expand parent folder if it exists
   148→        if (newFolder.parentId) {
   149→          get().expandFolder(newFolder.parentId);
   150→        }
   151→
   152→        log.debug('Folder created', { id: newFolder.id });
   153→        return newFolder;
   154→      },
   155→
   156→      getFolder: (id) => {
   157→        return get().folders[id];
   158→      },
   159→
   160→      updateFolder: (id, updates) => {
   161→        const folder = get().folders[id];
   162→        if (!folder) {
   163→          log.warn('Folder not found', { id });
   164→          return;
   165→        }
   166→
   167→        set((state) => ({
   168→          folders: {
   169→            ...state.folders,
   170→            [id]: {
   171→              ...folder,
   172→              ...updates,
   173→              updatedAt: new Date(),
   174→            },
   175→          },
   176→        }));
   177→        log.debug('Folder updated', { id });
   178→      },
   179→
   180→      deleteFolder: (id, deleteNotes = false) => {
   181→        // CRITICAL: Handle notes before deleting folder to prevent orphaned notes
   182→        // Get the folder being deleted
   183→        const folder = get().folders[id];
   184→        if (!folder) {
   185→          log.warn('Folder not found for deletion', { id });
   186→          return;
   187→        }
   188→
   189→        // Get all descendant folders
   190→        const descendants = get()
   191→          .getFlatTree()
   192→          .filter((f) => get().isDescendantOf(f.id, id));
   193→
   194→        // Get all folder IDs that will be deleted (this folder + descendants)
   195→        const foldersToDelete = [id, ...descendants.map(d => d.id)];
   196→
   197→        // Handle notes in deleted folders
   198→        try {
   199→          const notesStore = useNotesStore.getState();
   200→
   201→          // Get all notes in folders that will be deleted
   202→          const notesInDeletedFolders = notesStore.getAllNotes()
   203→            .filter((note: { folderId: string | null }) =>
   204→              note.folderId && foldersToDelete.includes(note.folderId)
   205→            );
   206→
   207→          if (notesInDeletedFolders.length > 0) {
   208→            if (deleteNotes) {
   209→              // Delete all notes in folder and descendants
   210→              const noteIds = notesInDeletedFolders.map((n: { id: string }) => n.id);
   211→              notesStore.deleteNotes(noteIds);
   212→              log.info('Deleted notes from deleted folders', { count: noteIds.length });
   213→            } else {
   214→              // Move notes to parent folder (or root if no parent)
   215→              const newFolderId = folder.parentId || null;
   216→              const noteIds = notesInDeletedFolders.map((n: { id: string }) => n.id);
   217→              notesStore.moveNotesToFolder(noteIds, newFolderId);
   218→              log.info('Moved notes', { count: noteIds.length, targetFolder: newFolderId || 'root' });
   219→            }
   220→          }
   221→        } catch (error) {
   222→          log.error('Error handling notes in deleted folder', { error });
   223→          // Continue with folder deletion even if note handling fails
   224→        }
   225→
   226→        // Now safe to delete folders
   227→        set((state) => {
   228→          const { [id]: deleted, ...remainingFolders } = state.folders;
   229→
   230→          // Also delete descendants
   231→          descendants.forEach((desc) => {
   232→            delete remainingFolders[desc.id];
   233→          });
   234→
   235→          // Remove from expanded set
   236→          const newExpanded = new Set(state.expandedFolderIds);
   237→          newExpanded.delete(id);
   238→          descendants.forEach((desc) => newExpanded.delete(desc.id));
   239→
   240→          return {
   241→            folders: remainingFolders,
   242→            expandedFolderIds: newExpanded,
   243→            activeFolderId: state.activeFolderId === id ? null : state.activeFolderId,
   244→          };
   245→        });
   246→
   247→        log.info('Folder deleted', { id, descendantCount: descendants.length });
   248→      },
   249→
   250→      duplicateFolder: (id) => {
   251→        const original = get().folders[id];
   252→        if (!original) {
   253→          log.warn('Folder not found for duplication', { id });
   254→          return null;
   255→        }
   256→
   257→        const duplicate = createDefaultFolder({
   258→          ...original,
   259→          name: `${original.name} (Copy)`,
   260→        });
   261→
   262→        set((state) => ({
   263→          folders: {
   264→            ...state.folders,
   265→            [duplicate.id]: duplicate,
   266→          },
   267→        }));
   268→
   269→        log.debug('Folder duplicated', { originalId: id, newId: duplicate.id });
   270→        return duplicate;
   271→      },
   272→
   273→      // Hierarchy operations
   274→      moveFolder: (folderId, newParentId) => {
   275→        if (!get().canMoveFolder(folderId, newParentId)) {
   276→          log.warn('Cannot move folder', { folderId, targetParentId: newParentId });
   277→          return;
   278→        }
   279→
   280→        const folder = get().folders[folderId];
   281→        if (!folder) return;
   282→
   283→        set((state) => ({
   284→          folders: {
   285→            ...state.folders,
   286→            [folderId]: {
   287→              ...folder,
   288→              parentId: newParentId,
   289→              updatedAt: new Date(),
   290→            },
   291→          },
   292→        }));
   293→
   294→        log.debug('Folder moved', { folderId, newParentId });
   295→      },
   296→
   297→      getChildren: (parentId) => {
   298→        return Object.values(get().folders)
   299→          .filter((f) => f.parentId === parentId)
   300→          .sort((a, b) => a.name.localeCompare(b.name)); // Sort alphabetically
   301→      },
   302→
   303→      getParent: (folderId) => {
   304→        const folder = get().folders[folderId];
   305→        if (!folder || !folder.parentId) return null;
   306→        return get().folders[folder.parentId] || null;
   307→      },
   308→
   309→      getPath: (folderId) => {
   310→        const path: Folder[] = [];
   311→        let current: Folder | undefined = get().folders[folderId];
   312→
   313→        while (current) {
   314→          path.unshift(current);
   315→          current = current.parentId ? get().folders[current.parentId] : undefined;
   316→        }
   317→
   318→        return path;
   319→      },
   320→
   321→      getDepth: (folderId) => {
   322→        if (!folderId) return 0;
   323→
   324→        let depth = 0;
   325→        let current = get().folders[folderId];
   326→
   327→        while (current?.parentId) {
   328→          depth++;
   329→          current = get().folders[current.parentId];
   330→
   331→          // Prevent infinite loops
   332→          if (depth > 100) {
   333→            log.error('Circular folder reference detected');
   334→            return depth;
   335→          }
   336→        }
   337→
   338→        return depth;
   339→      },
   340→
   341→      getFlatTree: () => {
   342→        return Object.values(get().folders).sort((a, b) =>
   343→          a.name.localeCompare(b.name)
   344→        );
   345→      },
   346→
   347→      getTree: () => {
   348→        const folders = Object.values(get().folders);
   349→
   350→        // Get real note counts from Notes store
   351→        const notesCountMap: Record<string, number> = {};
   352→        try {
   353→          const notes = useNotesStore.getState().getAllNotes();
   354→
   355→          // Count notes per folder (excluding archived notes)
   356→          notes
   357→            .filter((note: { isArchived: boolean }) => !note.isArchived)
   358→            .forEach((note: { folderId: string | null }) => {
   359→              const folderId = note.folderId || 'root';
   360→              notesCountMap[folderId] = (notesCountMap[folderId] || 0) + 1;
   361→            });
   362→        } catch (error) {
   363→          log.error('Error getting note counts', { error });
   364→          // Continue with empty counts if Notes store not available
   365→        }
   366→
   367→        return buildTree(folders, null, 0, notesCountMap);
   368→      },
   369→
   370→      // Expand/Collapse
   371→      toggleExpanded: (id) => {
   372→        set((state) => {
   373→          const newExpanded = new Set(state.expandedFolderIds);
   374→          if (newExpanded.has(id)) {
   375→            newExpanded.delete(id);
   376→          } else {
   377→            newExpanded.add(id);
   378→          }
   379→          return { expandedFolderIds: newExpanded };
   380→        });
   381→      },
   382→
   383→      expandFolder: (id) => {
   384→        set((state) => ({
   385→          expandedFolderIds: new Set([...state.expandedFolderIds, id]),
   386→        }));
   387→      },
   388→
   389→      collapseFolder: (id) => {
   390→        set((state) => {
   391→          const newExpanded = new Set(state.expandedFolderIds);
   392→          newExpanded.delete(id);
   393→          return { expandedFolderIds: newExpanded };
   394→        });
   395→      },
   396→
   397→      expandAll: () => {
   398→        const allIds = Object.keys(get().folders);
   399→        set({ expandedFolderIds: new Set(allIds) });
   400→        log.debug('Expanded all folders');
   401→      },
   402→
   403→      collapseAll: () => {
   404→        set({ expandedFolderIds: new Set() });
   405→        log.debug('Collapsed all folders');
   406→      },
   407→
   408→      expandPath: (folderId) => {
   409→        const path = get().getPath(folderId);
   410→        set((state) => {
   411→          const newExpanded = new Set(state.expandedFolderIds);
   412→          path.forEach((folder) => newExpanded.add(folder.id));
   413→          return { expandedFolderIds: newExpanded };
   414→        });
   415→      },
   416→
   417→      // UI state
   418→      setActiveFolder: (id) => {
   419→        set({ activeFolderId: id });
   420→      },
   421→
   422→      // Utility
   423→      canMoveFolder: (folderId, targetParentId) => {
   424→        // Can't move to self
   425→        if (folderId === targetParentId) return false;
   426→
   427→        // Can't move to own descendant (would create cycle)
   428→        if (targetParentId && get().isDescendantOf(targetParentId, folderId)) {
   429→          return false;
   430→        }
   431→
   432→        // Check max depth
   433→        const newDepth = get().getDepth(targetParentId || '') + 1;
   434→        if (newDepth >= FOLDER_CONSTANTS.MAX_DEPTH) {
   435→          return false;
   436→        }
   437→
   438→        return true;
   439→      },
   440→
   441→      isDescendantOf: (folderId, ancestorId) => {
   442→        let current = get().folders[folderId];
   443→        let iterations = 0;
   444→
   445→        while (current?.parentId) {
   446→          if (current.parentId === ancestorId) return true;
   447→          current = get().folders[current.parentId];
   448→
   449→          // Prevent infinite loops
   450→          if (iterations++ > 100) {
   451→            log.error('Circular folder reference detected');
   452→            return false;
   453→          }
   454→        }
   455→
   456→        return false;
   457→      },
   458→
   459→      exportFolders: () => {
   460→        return Object.values(get().folders);
   461→      },
   462→
   463→      importFolders: (folders, merge) => {
   464→        if (!merge) {
   465→          // Replace all folders
   466→          set({
   467→            folders: Object.fromEntries(folders.map((f) => [f.id, f])),
   468→            activeFolderId: null,
   469→            expandedFolderIds: new Set(),
   470→          });
   471→          log.info('Imported folders (replace mode)', { count: folders.length });
   472→        } else {
   473→          // Merge with existing folders
   474→          set((state) => {
   475→            const updatedFolders = { ...state.folders };
   476→            folders.forEach((folder) => {
   477→              updatedFolders[folder.id] = folder;
   478→            });
   479→            return { folders: updatedFolders };
   480→          });
   481→          log.info('Imported folders (merge mode)', { count: folders.length });
   482→        }
   483→      },
   484→
   485→      clearAllFolders: () => {
   486→        set({
   487→          folders: {},
   488→          activeFolderId: null,
   489→          expandedFolderIds: new Set(),
   490→        });
   491→        log.info('All folders cleared');
   492→      },
   493→    }),
   494→    {
   495→      name: 'folders', // IndexedDB key
   496→      storage: createJSONStorage(() => createSyncedStorage()),
   497→      partialize: (state) => ({
   498→        // Only persist folders, not UI state
   499→        // Convert Set to Array for JSON serialization
   500→        folders: state.folders,
   501→        expandedFolderIds: Array.from(state.expandedFolderIds),
   502→      }),
   503→      // Handle date serialization and Set restoration
   504→      onRehydrateStorage: () => (state) => {
   505→        log.debug('Folders store rehydrating');
   506→        if (state) {
   507→          try {
   508→            // Convert date strings back to Date objects
   509→            if (state.folders && typeof state.folders === 'object') {
   510→              Object.values(state.folders).forEach((folder) => {
   511→                if (typeof folder.createdAt === 'string') {
   512→                  folder.createdAt = new Date(folder.createdAt);
   513→                }
   514→                if (typeof folder.updatedAt === 'string') {
   515→                  folder.updatedAt = new Date(folder.updatedAt);
   516→                }
   517→              });
   518→            } else {
   519→              state.folders = {};
   520→            }
   521→
   522→            // CRITICAL: Fix corrupted Set data
   523→            const expandedIds = (state as any).expandedFolderIds;
   524→
   525→            if (expandedIds instanceof Set) {
   526→              // Already a Set (shouldn't happen after persist, but just in case)
   527→            } else if (Array.isArray(expandedIds)) {
   528→              // Correct format from our partialize
   529→              state.expandedFolderIds = new Set(expandedIds);
   530→            } else {
   531→              // Corrupted data - plain object or other
   532→              log.warn('Corrupted expandedFolderIds detected, resetting');
   533→              state.expandedFolderIds = new Set<string>();
   534→            }
   535→          } catch (err) {
   536→            log.error('Error during folders store rehydration', { error: err });
   537→            // Reset to safe defaults
   538→            state.folders = {};
   539→            state.expandedFolderIds = new Set<string>();
   540→            state.activeFolderId = null;
   541→          }
   542→        }
   543→        log.info('Folders store rehydrated', { folderCount: state?.folders ? Object.keys(state.folders).length : 0 });
   544→      },
   545→    }
   546→  )
   547→);
   548→
   549→/**
   550→ * Selector hooks for optimized re-renders
   551→ */
   552→export const useActiveFolder = () =>
   553→  useFoldersStore((state) => {
   554→    const activeId = state.activeFolderId;
   555→    return activeId ? state.folders[activeId] : null;
   556→  });
   557→
   558→export const useFolderTree = () =>
   559→  useFoldersStore((state) => state.getTree());
   560→
   561→export const useFolderPath = (folderId: string) =>
   562→  useFoldersStore((state) => state.getPath(folderId));
   563→
   564→export const isFolderExpanded = (folderId: string) =>
   565→  useFoldersStore((state) => state.expandedFolderIds.has(folderId));
   566→

