     1→/**
     2→ * FolderSidebar Component
     3→ *
     4→ * Folder tree sidebar with search and tag filtering.
     5→ * Extracted from Notes.tsx as part of the Notes Page Revolution.
     6→ *
     7→ * Features:
     8→ * - Hierarchical folder tree with expand/collapse
     9→ * - Search notes with Cmd+K shortcut
    10→ * - Tag filtering with TagFilter component
    11→ * - Folder CRUD operations (create, rename, delete)
    12→ * - Resizable via parent container
    13→ */
    14→
    15→import React, { useEffect, useState, useRef, useMemo } from 'react';
    16→import { FolderOpen } from 'lucide-react';
    17→import { useFoldersStore } from '../../stores/useFoldersStore';
    18→import { useNotesStore } from '../../stores/useNotesStore';
    19→import { useUndoStore } from '../../stores/useUndoStore';
    20→import { ConfirmDialog } from '../ConfirmDialog';
    21→import { PromptDialog } from '../PromptDialog';
    22→import { TagFilter } from '../TagFilter';
    23→import { FolderTreeNode } from './FolderTreeNode';
    24→import { logger } from '../../services/logger';
    25→
    26→const log = logger.module('FolderSidebar');
    27→
    28→export interface FolderSidebarProps {
    29→  activeTags: string[];
    30→  onAddTag: (tag: string) => void;
    31→  onRemoveTag: (tag: string) => void;
    32→  onClearAllTags: () => void;
    33→  onOpenTagManager: () => void;
    34→}
    35→
    36→export const FolderSidebar: React.FC<FolderSidebarProps> = ({
    37→  activeTags,
    38→  onAddTag,
    39→  onRemoveTag,
    40→  onClearAllTags,
    41→  onOpenTagManager,
    42→}) => {
    43→  // Get raw folders object (stable reference unless folders change)
    44→  const foldersObj = useFoldersStore((state) => state.folders);
    45→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
    46→  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
    47→  const createFolder = useFoldersStore((state) => state.createFolder);
    48→  const deleteFolder = useFoldersStore((state) => state.deleteFolder);
    49→  const updateFolder = useFoldersStore((state) => state.updateFolder);
    50→  const notesObj = useNotesStore((state) => state.notes);
    51→  const searchNotes = useNotesStore((state) => state.searchNotes);
    52→
    53→  // Dialog state
    54→  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
    55→  const [renameDialogOpen, setRenameDialogOpen] = useState(false);
    56→  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
    57→  const [selectedFolderName, setSelectedFolderName] = useState('');
    58→
    59→  // Search state
    60→  const [searchQuery, setSearchQuery] = useState('');
    61→  const searchInputRef = useRef<HTMLInputElement>(null);
    62→
    63→  // Keyboard shortcut for search (Cmd+K)
    64→  useEffect(() => {
    65→    const handleKeyDown = (e: KeyboardEvent) => {
    66→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
    67→        e.preventDefault();
    68→        searchInputRef.current?.focus();
    69→      }
    70→    };
    71→
    72→    window.addEventListener('keydown', handleKeyDown);
    73→    return () => window.removeEventListener('keydown', handleKeyDown);
    74→  }, []);
    75→
    76→  // Get tree structure for nested folders
    77→  const getTree = useFoldersStore((state) => state.getTree);
    78→  const toggleExpanded = useFoldersStore((state) => state.toggleExpanded);
    79→  const expandedFolderIds = useFoldersStore((state) => state.expandedFolderIds);
    80→
    81→  const folderTree = useMemo(() => getTree(), [foldersObj, getTree]);
    82→
    83→  // Get note count for a folder
    84→  const getFolderNoteCount = (folderId: string) => {
    85→    return Object.values(notesObj).filter((note) => note.folderId === folderId).length;
    86→  };
    87→
    88→  // Handle folder deletion
    89→  const handleDeleteFolder = (folderId: string, folderName: string) => {
    90→    setSelectedFolderId(folderId);
    91→    setSelectedFolderName(folderName);
    92→    setDeleteDialogOpen(true);
    93→  };
    94→
    95→  const confirmDeleteFolder = () => {
    96→    if (!selectedFolderId) return;
    97→
    98→    // Save folder and notes for undo
    99→    const folderToDelete = foldersObj[selectedFolderId];
   100→    if (!folderToDelete) {
   101→      log.warn('Folder not found', { folderId: selectedFolderId });
   102→      return;
   103→    }
   104→
   105→    const notesToDelete = Object.values(notesObj).filter(
   106→      (note) => note.folderId === selectedFolderId
   107→    );
   108→    const noteCount = notesToDelete.length;
   109→
   110→    // Delete all notes in this folder
   111→    notesToDelete.forEach((note) => {
   112→      useNotesStore.setState((state) => {
   113→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
   114→        return {
   115→          notes: remainingNotes,
   116→          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
   117→        };
   118→      });
   119→    });
   120→
   121→    // Delete the folder
   122→    deleteFolder(selectedFolderId);
   123→
   124→    log.info(`Folder "${folderToDelete.name}" deleted`, { noteCount });
   125→
   126→    // Add undo action to restore folder AND notes
   127→    useUndoStore.getState().addUndoAction(
   128→      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
   129→      () => {
   130→        // Restore the folder
   131→        useFoldersStore.setState((state) => ({
   132→          folders: {
   133→            ...state.folders,
   134→            [folderToDelete.id]: folderToDelete,
   135→          },
   136→        }));
   137→
   138→        // Restore all notes
   139→        useNotesStore.setState((state) => {
   140→          const restoredNotes = { ...state.notes };
   141→          notesToDelete.forEach((note) => {
   142→            restoredNotes[note.id] = note;
   143→          });
   144→          return {
   145→            notes: restoredNotes,
   146→          };
   147→        });
   148→
   149→        log.info(`Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
   150→      }
   151→    );
   152→  };
   153→
   154→  // Handle folder rename
   155→  const handleRenameFolder = (folderId: string, currentName: string) => {
   156→    setSelectedFolderId(folderId);
   157→    setSelectedFolderName(currentName);
   158→    setRenameDialogOpen(true);
   159→  };
   160→
   161→  const confirmRenameFolder = (newName: string) => {
   162→    if (!selectedFolderId || !newName.trim()) return;
   163→    updateFolder(selectedFolderId, { name: newName.trim() });
   164→  };
   165→
   166→  return (
   167→    <div className="h-full p-5 flex flex-col overflow-hidden border-b border-border-light dark:border-border-dark">
   168→      {/* Folders header */}
   169→      <div className="flex items-center justify-between mb-4 flex-shrink-0">
   170→        <h3 className="text-sm font-medium uppercase tracking-wide text-text-light-secondary dark:text-text-dark-secondary">
   171→          Folders
   172→        </h3>
   173→        <button
   174→          onClick={() => createFolder()}
   175→          className="text-xs px-3 h-8 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors font-medium"
   176→          title="New Folder"
   177→        >
   178→          + Folder
   179→        </button>
   180→      </div>
   181→
   182→      {/* Search Input */}
   183→      <div className="mb-3 flex-shrink-0">
   184→        <input
   185→          type="text"
   186→          placeholder="Search notes... (Cmd+K)"
   187→          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg
   188→                     bg-surface-light dark:bg-surface-dark
   189→                     text-text-light-primary dark:text-text-dark-primary
   190→                     placeholder-text-light-tertiary dark:placeholder-text-dark-tertiary
   191→                     focus:outline-none focus:ring-2 focus:ring-accent-cyan transition-all"
   192→          value={searchQuery}
   193→          onChange={(e) => setSearchQuery(e.target.value)}
   194→          ref={searchInputRef}
   195→        />
   196→      </div>
   197→
   198→      {/* All Notes (root level) */}
   199→      {!searchQuery.trim() && (
   200→        <button
   201→          onClick={() => setActiveFolder(null)}
   202→          className={`w-full text-left px-3 h-10 rounded-lg transition-colors mb-2 flex-shrink-0 flex items-center gap-2 ${
   203→            activeFolderId === null
   204→              ? 'bg-transparent border-l-2 border-accent-cyan dark:border-accent-magenta pl-[14px] text-accent-cyan dark:text-accent-magenta font-medium'
   205→              : 'border-l-2 border-transparent pl-[14px] hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary'
   206→          }`}
   207→        >
   208→          <FolderOpen className="w-4 h-4" />
   209→          <span className="text-sm font-medium">All Notes</span>
   210→        </button>
   211→      )}
   212→
   213→      {/* Search Results OR Folder list */}
   214→      {searchQuery.trim() ? (
   215→        /* Search Results */
   216→        <div className="overflow-y-auto flex-1 min-h-0">
   217→          <h3 className="text-xs font-medium uppercase tracking-wide text-text-light-tertiary dark:text-text-dark-tertiary mb-2">
   218→            {searchNotes(searchQuery).length} results for "{searchQuery}"
   219→          </h3>
   220→          <div className="space-y-2">
   221→            {searchNotes(searchQuery).map((note) => (
   222→              <div
   223→                key={note.id}
   224→                onClick={() => {
   225→                  setSearchQuery('');
   226→                  useNotesStore.getState().setActiveNote(note.id);
   227→                }}
   228→                className="p-3 rounded-lg cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   229→              >
   230→                <div className="font-medium text-sm text-text-light-primary dark:text-text-dark-primary mb-1 truncate">
   231→                  {note.title || 'Untitled'}
   232→                </div>
   233→                <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary line-clamp-2">
   234→                  {note.contentText?.slice(0, 150)}...
   235→                </div>
   236→                <div className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">
   237→                  {new Date(note.updatedAt).toLocaleDateString()}
   238→                </div>
   239→              </div>
   240→            ))}
   241→            {searchNotes(searchQuery).length === 0 && (
   242→              <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-8">
   243→                No notes found for "{searchQuery}"
   244→              </div>
   245→            )}
   246→          </div>
   247→        </div>
   248→      ) : (
   249→        /* Folder tree - Scrollable */
   250→        <div role="tree" className="space-y-1 overflow-y-auto flex-1 min-h-0">
   251→          {folderTree.map((node) => (
   252→            <FolderTreeNode
   253→              key={node.id}
   254→              node={node}
   255→              depth={0}
   256→              activeFolderId={activeFolderId}
   257→              expandedFolderIds={expandedFolderIds}
   258→              onSelect={setActiveFolder}
   259→              onToggleExpanded={toggleExpanded}
   260→              onDelete={handleDeleteFolder}
   261→              onRename={handleRenameFolder}
   262→              getFolderNoteCount={getFolderNoteCount}
   263→            />
   264→          ))}
   265→
   266→          {/* Empty state */}
   267→          {folderTree.length === 0 && (
   268→            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-4">
   269→              No folders yet
   270→            </div>
   271→          )}
   272→        </div>
   273→      )}
   274→
   275→      {/* Tag Filter Section */}
   276→      <div className="pt-3 border-t border-border-light dark:border-border-dark mt-3 flex-shrink-0">
   277→        <TagFilter
   278→          activeTags={activeTags}
   279→          onAddTag={onAddTag}
   280→          onRemoveTag={onRemoveTag}
   281→          onClearAll={onClearAllTags}
   282→        />
   283→        <button
   284→          onClick={onOpenTagManager}
   285→          className="w-full mt-3 px-3 py-2 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-colors"
   286→        >
   287→          Manage Tags
   288→        </button>
   289→      </div>
   290→
   291→      {/* Delete Folder Confirmation Dialog */}
   292→      <ConfirmDialog
   293→        isOpen={deleteDialogOpen}
   294→        onClose={() => setDeleteDialogOpen(false)}
   295→        onConfirm={confirmDeleteFolder}
   296→        title="Delete Folder"
   297→        message={`Delete folder "${selectedFolderName}"? This will also delete ${selectedFolderId ? getFolderNoteCount(selectedFolderId) : 0} note(s) inside.`}
   298→        confirmText="Delete"
   299→        variant="danger"
   300→      />
   301→
   302→      {/* Rename Folder Prompt Dialog */}
   303→      <PromptDialog
   304→        isOpen={renameDialogOpen}
   305→        onClose={() => setRenameDialogOpen(false)}
   306→        onConfirm={confirmRenameFolder}
   307→        title="Rename Folder"
   308→        message="Enter a new name for this folder:"
   309→        defaultValue={selectedFolderName}
   310→        placeholder="Folder name"
   311→        confirmText="Rename"
   312→      />
   313→    </div>
   314→  );
   315→};
   316→

