     1→/**
     2→ * FileTreeLayout Component
     3→ *
     4→ * Obsidian/VS Code-inspired 2-column layout for Notes page.
     5→ * Layout: Unified File Tree | Editor
     6→ *
     7→ * Features:
     8→ * - Single sidebar with folders containing notes directly
     9→ * - Notes appear as children of their parent folders
    10→ * - Collapsible folders with nested notes
    11→ * - Editor fills remaining space (full height)
    12→ * - Search and filter at top of tree
    13→ * - Clean, code-editor-like aesthetic
    14→ */
    15→
    16→import React, { useCallback, useMemo, useRef, useState } from 'react';
    17→import { motion, AnimatePresence } from 'framer-motion';
    18→import {
    19→  ChevronDown,
    20→  ChevronRight,
    21→  FileText,
    22→  Folder as FolderIcon,
    23→  FolderOpen,
    24→  PanelLeftClose,
    25→  PanelLeftOpen,
    26→  Search,
    27→  Settings2,
    28→  Plus,
    29→  Star,
    30→  Pin,
    31→} from 'lucide-react';
    32→import { useSettingsStore } from '../../stores/useSettingsStore';
    33→import { useFoldersStore } from '../../stores/useFoldersStore';
    34→import { useNotesStore } from '../../stores/useNotesStore';
    35→import type { Folder, Note } from '../../types/notes';
    36→import { SidebarResizer } from './SidebarResizer';
    37→import { useReducedMotion } from '../../hooks/useReducedMotion';
    38→
    39→export interface FileTreeLayoutProps {
    40→  /** Content to render in the editor pane */
    41→  children: React.ReactNode;
    42→  /** Active tag filters */
    43→  activeTags: string[];
    44→  /** Callback to add a tag filter */
    45→  onAddTag: (tag: string) => void;
    46→  /** Callback to remove a tag filter */
    47→  onRemoveTag: (tag: string) => void;
    48→  /** Callback to clear all tag filters */
    49→  onClearAllTags: () => void;
    50→  /** Callback to open tag manager modal */
    51→  onOpenTagManager: () => void;
    52→  /** Callback to open template library modal */
    53→  onOpenTemplateLibrary: () => void;
    54→  /** Callback to open export modal */
    55→  onOpenExportModal: () => void;
    56→  /** Callback to open layout settings */
    57→  onOpenLayoutSettings?: () => void;
    58→}
    59→
    60→interface FileTreeNodeProps {
    61→  folder: Folder;
    62→  notes: Note[];
    63→  depth: number;
    64→  expandedFolders: Set<string>;
    65→  activeNoteId: string | null;
    66→  onToggleFolder: (folderId: string) => void;
    67→  onSelectNote: (noteId: string) => void;
    68→  onCreateNote: (folderId: string | null) => void;
    69→  getChildFolders: (parentId: string | null) => Folder[];
    70→  getNotesByFolder: (folderId: string | null) => Note[];
    71→  prefersReducedMotion: boolean;
    72→}
    73→
    74→// Animation variants for folder children
    75→const getChildrenVariants = (reduceMotion: boolean) => ({
    76→  hidden: {
    77→    opacity: reduceMotion ? 1 : 0,
    78→    height: 0,
    79→    transition: { duration: reduceMotion ? 0 : 0.15, ease: 'easeInOut' as const },
    80→  },
    81→  visible: {
    82→    opacity: 1,
    83→    height: 'auto',
    84→    transition: { duration: reduceMotion ? 0 : 0.15, ease: 'easeInOut' as const },
    85→  },
    86→});
    87→
    88→// File tree node (recursive)
    89→const FileTreeNode: React.FC<FileTreeNodeProps> = ({
    90→  folder,
    91→  notes,
    92→  depth,
    93→  expandedFolders,
    94→  activeNoteId,
    95→  onToggleFolder,
    96→  onSelectNote,
    97→  onCreateNote,
    98→  getChildFolders,
    99→  getNotesByFolder,
   100→  prefersReducedMotion,
   101→}) => {
   102→  const isExpanded = expandedFolders.has(folder.id);
   103→  const childFolders = getChildFolders(folder.id);
   104→  const folderNotes = getNotesByFolder(folder.id);
   105→  const hasChildren = childFolders.length > 0 || folderNotes.length > 0;
   106→
   107→  const childrenVariants = useMemo(
   108→    () => getChildrenVariants(prefersReducedMotion),
   109→    [prefersReducedMotion]
   110→  );
   111→
   112→  return (
   113→    <div>
   114→      {/* Folder row */}
   115→      <div
   116→        className="group flex items-center gap-1 px-2 py-1.5 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded-md cursor-pointer transition-colors"
   117→        style={{ paddingLeft: `${depth * 12 + 8}px` }}
   118→        onClick={() => onToggleFolder(folder.id)}
   119→      >
   120→        {/* Expand/collapse chevron */}
   121→        {hasChildren ? (
   122→          <span className="text-text-light-tertiary dark:text-text-dark-tertiary">
   123→            {isExpanded ? (
   124→              <ChevronDown className="w-3.5 h-3.5" />
   125→            ) : (
   126→              <ChevronRight className="w-3.5 h-3.5" />
   127→            )}
   128→          </span>
   129→        ) : (
   130→          <span className="w-3.5" />
   131→        )}
   132→
   133→        {/* Folder icon */}
   134→        {isExpanded ? (
   135→          <FolderOpen className="w-4 h-4 text-accent-cyan dark:text-accent-magenta flex-shrink-0" />
   136→        ) : (
   137→          <FolderIcon className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary flex-shrink-0" />
   138→        )}
   139→
   140→        {/* Folder name */}
   141→        <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary truncate flex-1">
   142→          {folder.name}
   143→        </span>
   144→
   145→        {/* Quick add note button (on hover) */}
   146→        <button
   147→          onClick={(e) => {
   148→            e.stopPropagation();
   149→            onCreateNote(folder.id);
   150→          }}
   151→          className="opacity-0 group-hover:opacity-100 p-1 rounded hover:bg-surface-light dark:hover:bg-surface-dark transition-all"
   152→          title="New note in folder"
   153→          aria-label="Create new note in folder"
   154→        >
   155→          <Plus className="w-3 h-3 text-text-light-tertiary dark:text-text-dark-tertiary" />
   156→        </button>
   157→      </div>
   158→
   159→      {/* Children (folders + notes) */}
   160→      <AnimatePresence initial={false}>
   161→        {isExpanded && hasChildren && (
   162→          <motion.div
   163→            className="overflow-hidden"
   164→            initial="hidden"
   165→            animate="visible"
   166→            exit="hidden"
   167→            variants={childrenVariants}
   168→          >
   169→            {/* Child folders first */}
   170→            {childFolders.map((child) => (
   171→              <FileTreeNode
   172→                key={child.id}
   173→                folder={child}
   174→                notes={notes}
   175→                depth={depth + 1}
   176→                expandedFolders={expandedFolders}
   177→                activeNoteId={activeNoteId}
   178→                onToggleFolder={onToggleFolder}
   179→                onSelectNote={onSelectNote}
   180→                onCreateNote={onCreateNote}
   181→                getChildFolders={getChildFolders}
   182→                getNotesByFolder={getNotesByFolder}
   183→                prefersReducedMotion={prefersReducedMotion}
   184→              />
   185→            ))}
   186→
   187→            {/* Notes in this folder */}
   188→            {folderNotes.map((note) => (
   189→              <div
   190→                key={note.id}
   191→                className={`group flex items-center gap-1.5 px-2 py-1.5 rounded-md cursor-pointer transition-colors ${
   192→                  activeNoteId === note.id
   193→                    ? 'bg-accent-cyan/10 dark:bg-accent-magenta/10 border-l-2 border-accent-cyan dark:border-accent-magenta'
   194→                    : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   195→                }`}
   196→                style={{ paddingLeft: `${(depth + 1) * 12 + 8}px` }}
   197→                onClick={() => onSelectNote(note.id)}
   198→              >
   199→                {/* Spacer for alignment with folder chevrons */}
   200→                <span className="w-3.5" />
   201→
   202→                {/* Note icon */}
   203→                <FileText
   204→                  className={`w-4 h-4 flex-shrink-0 ${
   205→                    activeNoteId === note.id
   206→                      ? 'text-accent-cyan dark:text-accent-magenta'
   207→                      : 'text-text-light-tertiary dark:text-text-dark-tertiary'
   208→                  }`}
   209→                />
   210→
   211→                {/* Note title */}
   212→                <span
   213→                  className={`text-sm truncate flex-1 ${
   214→                    activeNoteId === note.id
   215→                      ? 'font-medium text-accent-cyan dark:text-accent-magenta'
   216→                      : 'text-text-light-primary dark:text-text-dark-primary'
   217→                  }`}
   218→                >
   219→                  {note.title || 'Untitled'}
   220→                </span>
   221→
   222→                {/* Indicators */}
   223→                <div className="flex items-center gap-0.5">
   224→                  {note.isPinned && (
   225→                    <Pin className="w-3 h-3 text-accent-purple" />
   226→                  )}
   227→                  {note.isFavorite && (
   228→                    <Star className="w-3 h-3 text-accent-yellow fill-accent-yellow" />
   229→                  )}
   230→                </div>
   231→              </div>
   232→            ))}
   233→          </motion.div>
   234→        )}
   235→      </AnimatePresence>
   236→    </div>
   237→  );
   238→};
   239→
   240→export const FileTreeLayout: React.FC<FileTreeLayoutProps> = ({
   241→  children,
   242→  activeTags,
   243→  onOpenLayoutSettings,
   244→}) => {
   245→  const sidebarRef = useRef<HTMLDivElement>(null);
   246→  const prefersReducedMotion = useReducedMotion();
   247→
   248→  // Sidebar collapse state
   249→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
   250→  const [searchQuery, setSearchQuery] = useState('');
   251→  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set());
   252→
   253→  // Get layout preferences
   254→  const notesLayout = useSettingsStore((state) => state.notesLayout);
   255→  const setNotesLayout = useSettingsStore((state) => state.setNotesLayout);
   256→  const { sidebarWidth } = notesLayout;
   257→
   258→  // Get folders and notes
   259→  const foldersObj = useFoldersStore((state) => state.folders);
   260→  const notesObj = useNotesStore((state) => state.notes);
   261→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   262→  const setActiveNote = useNotesStore((state) => state.setActiveNote);
   263→  const createNote = useNotesStore((state) => state.createNote);
   264→
   265→  // Convert objects to arrays
   266→  const notes = useMemo(() => Object.values(notesObj), [notesObj]);
   267→  const folders = useMemo(() => Object.values(foldersObj), [foldersObj]);
   268→
   269→  // Filter notes by search query and tags
   270→  const filteredNotes = useMemo(() => {
   271→    let result = notes;
   272→
   273→    // Filter by search query
   274→    if (searchQuery.trim()) {
   275→      const query = searchQuery.toLowerCase();
   276→      result = result.filter(
   277→        (note) =>
   278→          note.title.toLowerCase().includes(query) ||
   279→          note.content.toLowerCase().includes(query)
   280→      );
   281→    }
   282→
   283→    // Filter by active tags
   284→    if (activeTags.length > 0) {
   285→      result = result.filter((note) =>
   286→        activeTags.every((tag) => note.tags.includes(tag))
   287→      );
   288→    }
   289→
   290→    return result;
   291→  }, [notes, searchQuery, activeTags]);
   292→
   293→  // Get child folders for a parent
   294→  const getChildFolders = useCallback(
   295→    (parentId: string | null): Folder[] => {
   296→      return folders.filter((f) => f.parentId === parentId);
   297→    },
   298→    [folders]
   299→  );
   300→
   301→  // Get notes by folder (filtered)
   302→  const getNotesByFolder = useCallback(
   303→    (folderId: string | null): Note[] => {
   304→      return filteredNotes.filter((n) => n.folderId === folderId);
   305→    },
   306→    [filteredNotes]
   307→  );
   308→
   309→  // Get root folders
   310→  const rootFolders = useMemo(
   311→    () => folders.filter((f) => f.parentId === null),
   312→    [folders]
   313→  );
   314→
   315→  // Get root-level notes (no folder)
   316→  const rootNotes = useMemo(
   317→    () => filteredNotes.filter((n) => n.folderId === null),
   318→    [filteredNotes]
   319→  );
   320→
   321→  // Handle folder toggle
   322→  const toggleFolder = useCallback((folderId: string) => {
   323→    setExpandedFolders((prev) => {
   324→      const next = new Set(prev);
   325→      if (next.has(folderId)) {
   326→        next.delete(folderId);
   327→      } else {
   328→        next.add(folderId);
   329→      }
   330→      return next;
   331→    });
   332→  }, []);
   333→
   334→  // Handle note selection
   335→  const handleSelectNote = useCallback(
   336→    (noteId: string) => {
   337→      setActiveNote(noteId);
   338→    },
   339→    [setActiveNote]
   340→  );
   341→
   342→  // Handle create note
   343→  const handleCreateNote = useCallback(
   344→    (folderId: string | null) => {
   345→      createNote({ folderId });
   346→      // Expand the folder if creating inside one
   347→      if (folderId) {
   348→        setExpandedFolders((prev) => new Set([...prev, folderId]));
   349→      }
   350→    },
   351→    [createNote]
   352→  );
   353→
   354→  // Handle sidebar width change
   355→  const handleWidthChange = useCallback(
   356→    (width: number) => {
   357→      setNotesLayout({ sidebarWidth: width });
   358→    },
   359→    [setNotesLayout]
   360→  );
   361→
   362→  // Toggle sidebar
   363→  const toggleSidebar = useCallback(() => {
   364→    setIsSidebarCollapsed((prev) => !prev);
   365→  }, []);
   366→
   367→  return (
   368→    <div className="flex-1 flex min-h-0 overflow-hidden bg-surface-light dark:bg-surface-dark">
   369→      {/* Sidebar: File Tree */}
   370→      <AnimatePresence mode="wait">
   371→        {!isSidebarCollapsed && (
   372→          <motion.div
   373→            ref={sidebarRef}
   374→            initial={{ width: 0, opacity: 0 }}
   375→            animate={{ width: Math.max(sidebarWidth, 200), opacity: 1 }}
   376→            exit={{ width: 0, opacity: 0 }}
   377→            transition={{ duration: 0.2, ease: 'easeInOut' }}
   378→            className="flex-shrink-0 flex flex-col min-h-0 min-w-0 border-r border-border-light dark:border-border-dark relative overflow-hidden"
   379→            style={{ width: Math.max(sidebarWidth, 200) }}
   380→          >
   381→            {/* Header */}
   382→            <div className="flex items-center justify-between px-3 py-2 border-b border-border-light dark:border-border-dark flex-shrink-0">
   383→              <span className="text-xs font-medium uppercase tracking-wide text-text-light-tertiary dark:text-text-dark-tertiary">
   384→                Explorer
   385→              </span>
   386→              <div className="flex items-center gap-1">
   387→                <button
   388→                  onClick={() => handleCreateNote(null)}
   389→                  className="p-1.5 rounded-md hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   390→                  title="New note"
   391→                  aria-label="Create new note"
   392→                >
   393→                  <Plus className="w-3.5 h-3.5 text-text-light-tertiary dark:text-text-dark-tertiary" />
   394→                </button>
   395→                {onOpenLayoutSettings && (
   396→                  <button
   397→                    onClick={onOpenLayoutSettings}
   398→                    className="p-1.5 rounded-md hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   399→                    title="Layout settings"
   400→                    aria-label="Open layout settings"
   401→                  >
   402→                    <Settings2 className="w-3.5 h-3.5 text-text-light-tertiary dark:text-text-dark-tertiary" />
   403→                  </button>
   404→                )}
   405→                <button
   406→                  onClick={toggleSidebar}
   407→                  className="p-1.5 rounded-md hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   408→                  title="Collapse sidebar"
   409→                  aria-label="Collapse sidebar"
   410→                >
   411→                  <PanelLeftClose className="w-3.5 h-3.5 text-text-light-primary dark:text-text-dark-primary" />
   412→                </button>
   413→              </div>
   414→            </div>
   415→
   416→            {/* Search */}
   417→            <div className="px-3 py-2 border-b border-border-light dark:border-border-dark flex-shrink-0">
   418→              <div className="relative">
   419→                <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-text-light-tertiary dark:text-text-dark-tertiary" />
   420→                <input
   421→                  type="text"
   422→                  placeholder="Search notes..."
   423→                  value={searchQuery}
   424→                  onChange={(e) => setSearchQuery(e.target.value)}
   425→                  className="w-full pl-8 pr-3 py-1.5 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-md focus:outline-none focus:ring-1 focus:ring-accent-cyan dark:focus:ring-accent-magenta text-text-light-primary dark:text-text-dark-primary placeholder:text-text-light-tertiary dark:placeholder:text-text-dark-tertiary"
   426→                />
   427→              </div>
   428→            </div>
   429→
   430→            {/* File Tree */}
   431→            <div className="flex-1 min-h-0 overflow-y-auto py-2">
   432→              {/* Root folders */}
   433→              {rootFolders.map((folder) => (
   434→                <FileTreeNode
   435→                  key={folder.id}
   436→                  folder={folder}
   437→                  notes={filteredNotes}
   438→                  depth={0}
   439→                  expandedFolders={expandedFolders}
   440→                  activeNoteId={activeNoteId}
   441→                  onToggleFolder={toggleFolder}
   442→                  onSelectNote={handleSelectNote}
   443→                  onCreateNote={handleCreateNote}
   444→                  getChildFolders={getChildFolders}
   445→                  getNotesByFolder={getNotesByFolder}
   446→                  prefersReducedMotion={prefersReducedMotion}
   447→                />
   448→              ))}
   449→
   450→              {/* Root-level notes (no folder) */}
   451→              {rootNotes.length > 0 && (
   452→                <div className="mt-2 pt-2 border-t border-border-light/50 dark:border-border-dark/50">
   453→                  {rootNotes.map((note) => (
   454→                    <div
   455→                      key={note.id}
   456→                      className={`group flex items-center gap-1.5 px-2 py-1.5 mx-1 rounded-md cursor-pointer transition-colors ${
   457→                        activeNoteId === note.id
   458→                          ? 'bg-accent-cyan/10 dark:bg-accent-magenta/10 border-l-2 border-accent-cyan dark:border-accent-magenta'
   459→                          : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   460→                      }`}
   461→                      onClick={() => handleSelectNote(note.id)}
   462→                    >
   463→                      <FileText
   464→                        className={`w-4 h-4 flex-shrink-0 ${
   465→                          activeNoteId === note.id
   466→                            ? 'text-accent-cyan dark:text-accent-magenta'
   467→                            : 'text-text-light-tertiary dark:text-text-dark-tertiary'
   468→                        }`}
   469→                      />
   470→                      <span
   471→                        className={`text-sm truncate flex-1 ${
   472→                          activeNoteId === note.id
   473→                            ? 'font-medium text-accent-cyan dark:text-accent-magenta'
   474→                            : 'text-text-light-primary dark:text-text-dark-primary'
   475→                        }`}
   476→                      >
   477→                        {note.title || 'Untitled'}
   478→                      </span>
   479→                      <div className="flex items-center gap-0.5">
   480→                        {note.isPinned && (
   481→                          <Pin className="w-3 h-3 text-accent-purple" />
   482→                        )}
   483→                        {note.isFavorite && (
   484→                          <Star className="w-3 h-3 text-accent-yellow fill-accent-yellow" />
   485→                        )}
   486→                      </div>
   487→                    </div>
   488→                  ))}
   489→                </div>
   490→              )}
   491→
   492→              {/* Empty state */}
   493→              {rootFolders.length === 0 && rootNotes.length === 0 && (
   494→                <div className="px-4 py-8 text-center">
   495→                  <FileText className="w-8 h-8 text-text-light-tertiary dark:text-text-dark-tertiary mx-auto mb-2" />
   496→                  <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   497→                    No notes yet
   498→                  </p>
   499→                  <button
   500→                    onClick={() => handleCreateNote(null)}
   501→                    className="mt-2 text-sm text-accent-cyan dark:text-accent-magenta hover:underline"
   502→                  >
   503→                    Create your first note
   504→                  </button>
   505→                </div>
   506→              )}
   507→            </div>
   508→
   509→            {/* Resize handle */}
   510→            <SidebarResizer
   511→              currentWidth={sidebarWidth}
   512→              minWidth={200}
   513→              maxWidth={400}
   514→              defaultWidth={280}
   515→              onWidthChange={handleWidthChange}
   516→            />
   517→          </motion.div>
   518→        )}
   519→      </AnimatePresence>
   520→
   521→      {/* Expand button (shown when collapsed) */}
   522→      {isSidebarCollapsed && (
   523→        <div className="flex-shrink-0 flex flex-col border-r border-border-light dark:border-border-dark">
   524→          <button
   525→            onClick={toggleSidebar}
   526→            className="p-2 m-1 rounded-md hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   527→            title="Expand sidebar"
   528→            aria-label="Expand sidebar"
   529→          >
   530→            <PanelLeftOpen className="w-4 h-4 text-text-light-primary dark:text-text-dark-primary" />
   531→          </button>
   532→        </div>
   533→      )}
   534→
   535→      {/* Editor (fills remaining space) */}
   536→      <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
   537→        {children}
   538→      </div>
   539→    </div>
   540→  );
   541→};
